import React from "react";

export default function ProfileScreen({ user = { name: "", email: "", joinedDate: "" } }) {
  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Profile</h1>
      <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm space-y-4">
        <p><span className="font-semibold">Name:</span> {user.name}</p>
        <p><span className="font-semibold">Email:</span> {user.email}</p>
        <p><span className="font-semibold">Joined:</span> {user.joinedDate}</p>
      </div>
      <button className="mt-6 w-full py-3 bg-red-600 text-white rounded-xl hover:bg-red-700 transition-colors">
        Logout
      </button>
    </div>
  );
}
